// Нормализация входа из Mattermost (коннектор/бот → webhook).
// Тело вебхука: { channel_id, user_id, sender_name, message, file_ids }
const root = $input.first().json;
const b = root.body || root;
const channelId = b.channel_id || '';
const userId = b.user_id || '';
const senderName = b.sender_name || '';
const text = (b.message == null ? '' : String(b.message));
const fileIds = Array.isArray(b.file_ids) ? b.file_ids : [];

// Фото пока НЕ обрабатываем (отложено). Фиксируем факт вложения текстовым маркером.
let normalized_text = text;
if (!text && fileIds.length) {
  normalized_text = '[Пользователь прислал вложение без текста — разбор фото пока не поддержан, попроси описать доказательство текстом]';
} else if (!text) {
  normalized_text = '[Получено пустое сообщение — попроси повторить текстом]';
}

return [{ json: {
  chat_id: channelId,        // = channel_id (downstream ждёт chat_id)
  channel_id: channelId,
  user_id: userId,
  sender_name: senderName,
  normalized_text,
  file_ids: fileIds
} }];

// Единый инструмент дат: резолвит относительные даты И считает сроки ст.193.
// Вход query: даты в ГГГГ-ММ-ДД или ДД.ММ.ГГГГ, либо слова
// "сегодня/вчера/позавчера/завтра/послезавтра/N дней назад/через N дней",
// дни недели ("в среду", "в прошлый/позапрошлый вторник", "на этой/прошлой/позапрошлой неделе в пятницу")
// и недели как длительность ("неделю назад", "N недель назад", "через неделю/N недель").
// Ярлыки (необязательны): "violationDate=...; discoveryDate=..." (сначала нарушение).
// Сроки — буфер Контура (НЕ дословно ТК): нарушение +5 мес 15 дн; обнаружение +20 дн.
const text = String(query || '').toLowerCase();
const now = new Date();
const server = new Date(now.getFullYear(), now.getMonth(), now.getDate()); // локальная полночь
const pad = n => String(n).padStart(2,'0');
const fmt = d => `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`;
const addDays = (d,n) => { const x=new Date(d); x.setDate(x.getDate()+n); return x; };

function resolveOne(s){
  if(!s) return null;
  s = String(s).trim().toLowerCase();
  if(!s) return null;
  let m = s.match(/(\d{4})-(\d{2})-(\d{2})/);      if(m) return new Date(+m[1], +m[2]-1, +m[3]);
  m = s.match(/(\d{1,2})\.(\d{1,2})\.(\d{4})/);     if(m) return new Date(+m[3], +m[2]-1, +m[1]);
  if(/позавчера/.test(s)) return addDays(server,-2);
  if(/послезавтра/.test(s)) return addDays(server,2);
  if(/вчера/.test(s)) return addDays(server,-1);
  if(/(сегодня|сейчас|нынче|today)/.test(s)) return new Date(server);
  if(/завтра/.test(s)) return addDays(server,1);

  // недели как длительность: "N недель назад" / "через N недель" / "неделю назад" / "через неделю"
  m = s.match(/(\d+)\s*недел[а-яё]*\s*назад/);         if(m) return addDays(server,-7*(+m[1]));
  if(/недел[а-яё]*\s*назад/.test(s))                    return addDays(server,-7);
  m = s.match(/через\s*(\d+)\s*недел/);                if(m) return addDays(server,7*(+m[1]));
  if(/через\s*недел/.test(s))                           return addDays(server,7);

  // дни недели: голый день или "прошлый X" — ближайшее прошлое вхождение;
  // "позапрошлый X" — ещё на неделю раньше; "на этой/прошлой/позапрошлой неделе X" — конкретная календарная неделя.
  const WEEKDAYS = [
    { iso: 1, re: /понедельник/ },
    { iso: 2, re: /вторник/ },
    { iso: 3, re: /(среда|среду|среды|среде)/ },
    { iso: 4, re: /четверг/ },
    { iso: 5, re: /(пятница|пятницу|пятницы|пятнице)/ },
    { iso: 6, re: /(суббота|субботу|субботы|субботе)/ },
    { iso: 7, re: /воскресень/ },
  ];
  const wd = WEEKDAYS.find(w => w.re.test(s));
  if(wd){
    const todayIso = server.getDay() === 0 ? 7 : server.getDay();
    const daysAgo = ((todayIso - wd.iso + 7) % 7) || 7;
    const nearestPast = addDays(server, -daysAgo);
    const weekMode = /недел/.test(s);
    if(weekMode){
      const mondayOfThisWeek = addDays(server, -(todayIso - 1));
      let weeksBack = 0;
      if(/позапрошл/.test(s)) weeksBack = 2;
      else if(/прошл/.test(s)) weeksBack = 1;
      return addDays(mondayOfThisWeek, -7*weeksBack + (wd.iso - 1));
    }
    if(/позапрошл/.test(s)) return addDays(nearestPast, -7);
    return nearestPast;
  }

  m = s.match(/(\d+)\s*дн[а-яё]*\s*назад/);            if(m) return addDays(server,-(+m[1]));
  m = s.match(/через\s*(\d+)\s*дн/);               if(m) return addDays(server,+(+m[1]));
  return null;
}
function pick(label){
  const m = text.match(new RegExp(label+'\\s*=\\s*([^;]+)','i'));
  return m ? resolveOne(m[1]) : null;
}

let violationDate = pick('violationdate');
let discoveryDate = pick('discoverydate');
if(!violationDate || !discoveryDate){
  const toks = text.split(/[;,]/).map(resolveOne).filter(Boolean);
  if(!violationDate) violationDate = toks[0] || null;
  if(!discoveryDate) discoveryDate = toks[1] || toks[0] || null;
}
if(!violationDate){
  return JSON.stringify({ error: 'Не смог распознать дату нарушения. Передай дату нарушения (ГГГГ-ММ-ДД, «вчера/сегодня» или день недели, напр. «в прошлый вторник»).', received: String(query||'') });
}
if(!discoveryDate) discoveryDate = new Date(violationDate);

const vDeadline = new Date(violationDate); vDeadline.setMonth(vDeadline.getMonth()+5); vDeadline.setDate(vDeadline.getDate()+15);
const dDeadline = addDays(discoveryDate,20);
const expiredByViolation = server >= vDeadline;
const expiredByDiscovery = server >= dDeadline;
return JSON.stringify({
  violationDate: fmt(violationDate),
  discoveryDate: fmt(discoveryDate),
  isExpired: expiredByViolation || expiredByDiscovery,
  expiredReason: expiredByViolation ? 'violation_date' : (expiredByDiscovery ? 'discovery_date' : null),
  violationDeadline: fmt(vDeadline),
  discoveryDeadline: fmt(dDeadline),
  today: fmt(server)
});

// Формат ответа для Mattermost (markdown нативный) + разбивка на части.
const chatId = $('Нормализация входа TG').first().json.chat_id;
let t = String($json.output ?? '');
const LIMIT = 15000; // лимит поста MM ~16383, берём с запасом
const parts = [];
let buf = '';
for (const line of t.split('\n')) {
  if (buf.length + line.length + 1 > LIMIT) {
    if (buf) parts.push(buf);
    buf = line;
    while (buf.length > LIMIT) { parts.push(buf.slice(0, LIMIT)); buf = buf.slice(LIMIT); }
  } else {
    buf = buf ? buf + '\n' + line : line;
  }
}
if (buf) parts.push(buf);
if (!parts.length) parts.push('');
return parts.map(p => ({ json: { chat_id: chatId, text: p } }));

const prev = $('Нормализация входа TG').first().json;
const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
return [{ json: {
  chat_id: prev.chat_id,
  file_id: prev.evidence.file_id,
  file_size: prev.evidence.file_size,
  downloaded: true,
  note: 'telegram photo',
  file_b64: buf.toString('base64'),
  normalized_text: prev.normalized_text
} }];
